+    fn prepared_order_by_limit_rows(
+        &self,
+        root_page: i32,
+        order_source: PreparedMemValueSource,
+        rowid_alias_column_index: Option<usize>,
+        descending: bool,
+        nulls_order: NullsOrder,
+        limit: usize,
+    ) -> Option<Vec<Row>> {
+        let order_term = ResolvedOrderTerm {
+            column_index: 0,
+            descending,
+            nulls_order,
+        };
+        let winners = {
+            let db = self.db.borrow();
+            let table = db.get_table(root_page)?;
+            let mut winners: Vec<(SqliteValue, Row)> = Vec::with_capacity(limit);
+            for (rowid, row_values) in table.iter_rows() {
+                let order_value = memdb_row_value_with_source(
+                    rowid,
+                    row_values,
+                    order_source,
+                    rowid_alias_column_index,
+                );
+                let row = row_from_memdb_row_values(rowid, row_values, rowid_alias_column_index);
+                if winners.len() < limit {
+                    winners.push((order_value, row));
+                    continue;
+                }
+                let mut worst_idx = 0usize;
+                for idx in 1..winners.len() {
+                    if compare_order_values(&winners[idx].0, &winners[worst_idx].0, order_term)
+                        != std::cmp::Ordering::Less
+                    {
+                        worst_idx = idx;
+                    }
+                }
+                if compare_order_values(&order_value, &winners[worst_idx].0, order_term)
+                    == std::cmp::Ordering::Less
+                {
+                    winners[worst_idx] = (order_value, row);
+                }
+            }
+            winners
+        };
+        let mut winners = winners;
+        winners.sort_by(|left, right| compare_order_values(&left.0, &right.0, order_term));
+        Some(winners.into_iter().map(|(_, row)| row).collect())
+    }
