+fn prepared_count_having_filter(
+    expr: &Expr,
+    count_alias: Option<&str>,
+) -> Option<PreparedCountHavingFilter> {
+    fn expr_matches_count(expr: &Expr, count_alias: Option<&str>) -> bool {
+        match expr {
+            Expr::Column(column_ref, _) if column_ref.table.is_none() => {
+                count_alias.is_some_and(|alias| column_ref.column.eq_ignore_ascii_case(alias))
+            }
+            Expr::FunctionCall {
+                name,
+                args: FunctionArgs::Star,
+                distinct: false,
+                order_by,
+                filter: None,
+                over: None,
+                ..
+            } => name.eq_ignore_ascii_case("count") && order_by.is_empty(),
+            _ => false,
+        }
+    }
+
+    let Expr::BinaryOp {
+        left, op, right, ..
+    } = expr
+    else {
+        return None;
+    };
+
+    let normalize = |op: BinaryOp| match op {
+        BinaryOp::Gt => Some(PreparedCountHavingOp::GreaterThan),
+        BinaryOp::Ge => Some(PreparedCountHavingOp::GreaterThanOrEqual),
+        _ => None,
+    };
+    let flipped = |op: BinaryOp| match op {
+        BinaryOp::Lt => Some(PreparedCountHavingOp::GreaterThan),
+        BinaryOp::Le => Some(PreparedCountHavingOp::GreaterThanOrEqual),
+        _ => None,
+    };
+
+    if expr_matches_count(left, count_alias) {
+        return Some(PreparedCountHavingFilter {
+            op: normalize(*op)?,
+            threshold: select_numeric_literal(right)?,
+        });
+    }
+    if expr_matches_count(right, count_alias) {
+        return Some(PreparedCountHavingFilter {
+            op: flipped(*op)?,
+            threshold: select_numeric_literal(left)?,
+        });
+    }
+    None
+}
+
+fn prepared_count_having_matches(count: i64, filter: Option<&PreparedCountHavingFilter>) -> bool {
+    let Some(filter) = filter else {
+        return true;
+    };
+    let ordering = cmp_sqlite_values(&SqliteValue::Integer(count), &filter.threshold);
+    match filter.op {
+        PreparedCountHavingOp::GreaterThan => ordering == std::cmp::Ordering::Greater,
+        PreparedCountHavingOp::GreaterThanOrEqual => ordering != std::cmp::Ordering::Less,
+    }
+}
