+fn parse_ratio_env(key: &str, default: f64) -> Result<f64, Box<dyn Error>> {
+    let Some(raw) = std::env::var_os(key) else {
+        return Ok(default);
+    };
+    let text = raw.to_string_lossy();
+    let value: f64 = text
+        .parse()
+        .map_err(|error| format!("invalid {key} `{text}`: {error}"))?;
+    if !value.is_finite() || value <= 0.0 {
